// ── Parse Slack Slash Command Payload ──────────────────────────────
// Slack sends slash command data as URL-encoded form body.
// Fields: command, text, user_name, user_id, channel_name, channel_id,
//         team_id, response_url, trigger_id

const body = $input.first().json.body;

// URL-decode the body if it came as a raw string
let parsed = body;
if (typeof body === 'string') {
  parsed = {};
  body.split('&').forEach(pair => {
    const [k, v] = pair.split('=');
    parsed[decodeURIComponent(k)] = decodeURIComponent(v.replace(/\+/g, ' '));
  });
}

const command     = parsed.command     || '/ai';
const userText    = parsed.text        || '';
const userName    = parsed.user_name   || 'unknown';
const channelName = parsed.channel_name || 'unknown';
const responseUrl = parsed.response_url || '';

// Route to agent based on command text prefix
// e.g. 'kevin: draw a diagram' → Kevin personality
// e.g. 'jason: refactor this' → Jason personality
// default → round-robin or configured default agent

const AGENT_PREFIXES = ['kevin', 'jason', 'scaachi', 'christian', 'chidi'];
let agentName = 'jason';  // default agent
let taskText  = userText;

for (const name of AGENT_PREFIXES) {
  if (userText.toLowerCase().startsWith(name + ':')) {
    agentName = name;
    taskText  = userText.slice(name.length + 1).trim();
    break;
  }
}

return [{
  json: {
    command,
    rawText:     userText,
    taskText,
    agentName,
    userName,
    channelName,
    responseUrl,
    receivedAt:  new Date().toISOString()
  }
}];

// Extract Ollama response and prepare for Slack
const ollamaResponse = $input.first().json;
const upstream       = $('Parse Command').first().json;

const agentName  = upstream.agentName;
const taskText   = upstream.taskText;
const userName   = upstream.userName;
const responseUrl = upstream.responseUrl;

let responseText = ollamaResponse.response || 'No response from agent.';

// Truncate to Slack's 3000 char limit per block
if (responseText.length > 2800) {
  responseText = responseText.substring(0, 2800) + '\n... _(truncated)_';
}

const slackPayload = {
  response_type: 'in_channel',
  blocks: [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `:robot_face: *${agentName.charAt(0).toUpperCase() + agentName.slice(1)}* responding to @${userName}'s request:\n> ${taskText}`
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: responseText
      }
    },
    {
      type: 'context',
      elements: [
        {
          type: 'mrkdwn',
          text: `Via ai-workers · <!date^${Math.floor(Date.now()/1000)}^{time}|now>`
        }
      ]
    }
  ]
};

return [{
  json: {
    responseUrl,
    slackPayload
  }
}];
